import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Encode user input using ESAPI encoder to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Safe code: Properly encoded user input is embedded in the HTML response
        String htmlResponse = "<html><body>Welcome, " + encodedUserInput + "</body></html>";

        System.out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
